// Minimal msgpack decoder - handles arrays, fixints, uint8/16/32, int8/16/32,
// float32/64, fixstr, str8/16/32, nil, bool, used by rogue.io
(function (global) {
  'use strict';
  var msgpack = (global.msgpack = {});

  msgpack.encode = function (value) {
    var out = [];
    function writeVal(v) {
      if (v === null || v === undefined) {
        out.push(0xc0);
      } else if (v === false) {
        out.push(0xc2);
      } else if (v === true) {
        out.push(0xc3);
      } else if (typeof v === 'number') {
        if (Number.isInteger(v) && v >= 0 && v <= 0x7f) {
          out.push(v);                                        // positive fixint
        } else if (Number.isInteger(v) && v >= -32 && v < 0) {
          out.push(v & 0xff);                                 // negative fixint
        } else if (Number.isInteger(v) && v >= 0 && v <= 0xff) {
          out.push(0xcc, v);                                  // uint8
        } else if (Number.isInteger(v) && v >= 0 && v <= 0xffff) {
          out.push(0xcd, v >> 8, v & 0xff);                  // uint16
        } else {
          var dv = new DataView(new ArrayBuffer(8));          // float64
          dv.setFloat64(0, v, false);
          out.push(0xcb);
          for (var i = 0; i < 8; i++) out.push(dv.getUint8(i));
        }
      } else if (typeof v === 'string') {
        var sb = new TextEncoder().encode(v);
        if (sb.length <= 31) out.push(0xa0 | sb.length);
        else out.push(0xd9, sb.length & 0xff);
        for (var i = 0; i < sb.length; i++) out.push(sb[i]);
      } else if (Array.isArray(v)) {
        if (v.length <= 15) out.push(0x90 | v.length);
        else out.push(0xdc, v.length >> 8, v.length & 0xff);
        for (var i = 0; i < v.length; i++) writeVal(v[i]);
      }
    }
    writeVal(value);
    return new Uint8Array(out);
  };

  msgpack.decode = function (buffer) {
    var view =
      buffer instanceof DataView
        ? buffer
        : new DataView(
            buffer.buffer || buffer,
            buffer.byteOffset || 0,
            buffer.byteLength
          );
    var pos = 0;

    function read() {
      var b = view.getUint8(pos++);

      // positive fixint 0x00..0x7f
      if (b <= 0x7f) return b;
      // fixmap 0x80..0x8f
      if ((b & 0xf0) === 0x80) {
        var mlen = b & 0x0f;
        var map = {};
        for (var mi = 0; mi < mlen; mi++) {
          var mk = read();
          map[mk] = read();
        }
        return map;
      }
      // fixarray 0x90..0x9f
      if ((b & 0xf0) === 0x90) {
        var alen = b & 0x0f;
        var arr = [];
        for (var ai = 0; ai < alen; ai++) arr.push(read());
        return arr;
      }
      // fixstr 0xa0..0xbf
      if ((b & 0xe0) === 0xa0) {
        var slen = b & 0x1f;
        return readStr(slen);
      }
      // negative fixint 0xe0..0xff
      if (b >= 0xe0) return b - 256;

      switch (b) {
        case 0xc0:
          return null;
        case 0xc2:
          return false;
        case 0xc3:
          return true;
        case 0xca: {
          var f = view.getFloat32(pos, false);
          pos += 4;
          return f;
        }
        case 0xcb: {
          var d = view.getFloat64(pos, false);
          pos += 8;
          return d;
        }
        case 0xcc:
          return view.getUint8(pos++);
        case 0xcd: {
          var u16 = view.getUint16(pos, false);
          pos += 2;
          return u16;
        }
        case 0xce: {
          var u32 = view.getUint32(pos, false);
          pos += 4;
          return u32;
        }
        case 0xd0:
          return view.getInt8(pos++);
        case 0xd1: {
          var i16 = view.getInt16(pos, false);
          pos += 2;
          return i16;
        }
        case 0xd2: {
          var i32 = view.getInt32(pos, false);
          pos += 4;
          return i32;
        }
        case 0xd9: {
          var s8len = view.getUint8(pos++);
          return readStr(s8len);
        }
        case 0xda: {
          var s16len = view.getUint16(pos, false);
          pos += 2;
          return readStr(s16len);
        }
        case 0xdb: {
          var s32len = view.getUint32(pos, false);
          pos += 4;
          return readStr(s32len);
        }
        case 0xdc: {
          var a16len = view.getUint16(pos, false);
          pos += 2;
          var a16 = [];
          for (var i = 0; i < a16len; i++) a16.push(read());
          return a16;
        }
        case 0xdd: {
          var a32len = view.getUint32(pos, false);
          pos += 4;
          var a32 = [];
          for (var j = 0; j < a32len; j++) a32.push(read());
          return a32;
        }
        default:
          throw new Error('msgpack: unsupported type 0x' + b.toString(16) + ' at pos ' + (pos - 1));
      }
    }

    function readStr(len) {
      var bytes = new Uint8Array(view.buffer, view.byteOffset + pos, len);
      pos += len;
      return new TextDecoder().decode(bytes);
    }

    return read();
  };
})(typeof globalThis !== 'undefined' ? globalThis : typeof window !== 'undefined' ? window : this);
